def update():
    count = 0
    for actress_id, photos in GALLERY.items():
        if not photos:
            # For actresses with no wiki photos, use their main image as gallery
            doc = actresses_collection.find_one({"_id": actress_id})
            if doc and doc.get("image"):
                photos = [doc["image"]]
        actresses_collection.update_one(
            {"_id": actress_id},
            {"$set": {"gallery": photos}},
        )
        count += 1
    print(f"Updated gallery for {count} actresses.")


if __name__ == "__main__":
    update()
